// @generated-by: hand-written
// Generates naked iframe-target demo components into examples/.
//
// Reads:
//   - examples/_manifest.json      list of approved demo folders (relative to dev-app/src/app/demos/)
//   - dev-app/src/app/demos/**/*.story.ts
//
// Writes (overwriting only files marked @generated):
//   - examples/src/app/features/<demo>/<section-slug>.component.ts
//   - examples/src/app/app.routes.ts
//   - examples/src/app/_routes-meta.ts
//
// Re-run safely via: node scripts/generate-examples.mjs
import { readFile, writeFile, readdir, mkdir, rm } from 'node:fs/promises';
import { join, relative, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, '..');
const DEMOS_ROOT = join(ROOT, 'dev-app', 'src', 'app', 'demos');
const EXAMPLES_APP = join(ROOT, 'examples', 'src', 'app');
const FEATURES_DIR = join(EXAMPLES_APP, 'features');
const MANIFEST = join(ROOT, 'examples', '_manifest.json');

const GEN_HEADER = '// @generated by scripts/generate-examples.mjs — do not edit manually';

function kebabToPascal(s) {
  return s.split('-').map((p) => p.charAt(0).toUpperCase() + p.slice(1)).join('');
}

function slugify(s) {
  return s
    .toLowerCase()
    .replaceAll(/[^a-z0-9]+/g, '-')
    .replaceAll(/(^-|-$)/g, '');
}

/**
 * Drop a leading "CngxFoo — " prefix from a section title. Stories often
 * lead with the directive class name; the demo folder already conveys it,
 * so the slug only needs the descriptive remainder.
 *   "CngxFocusTrap — Modal Dialog" → "Modal Dialog"
 *   "Listbox with items input"     → "Listbox with items input"  (unchanged)
 */
function cleanSectionTitle(title) {
  return title.replace(/^Cngx[A-Z][A-Za-z0-9]*\s*[—–‒‐\-]+\s*/, '');
}

/**
 * Walk projects/**\/public-api.ts and build { className → '@cngx/<pkg>' } map
 * by parsing `export { … } from './…'` lines. Used to resolve section.imports
 * classes when the story is missing a moduleImports entry.
 */
async function* walkFiles(dir, predicate) {
  for (const e of await readdir(dir, { withFileTypes: true })) {
    const p = join(dir, e.name);
    if (e.isDirectory()) yield* walkFiles(p, predicate);
    else if (predicate(p)) yield p;
  }
}

async function buildPublicApiImportMap() {
  const map = new Map();
  const apis = [];
  for await (const f of walkFiles(join(ROOT, 'projects'), (p) => p.endsWith('/public-api.ts'))) {
    apis.push(relative(ROOT, f));
  }
  for (const rel of apis) {
    // projects/common/a11y/public-api.ts → @cngx/common/a11y
    // projects/common/public-api.ts      → @cngx/common
    const parts = rel.split('/').slice(1, -1);
    if (parts[0] === 'testing') continue;
    const pkg = '@cngx/' + parts.join('/');
    const src = await readFile(join(ROOT, rel), 'utf8');
    // Match: export { Name, Name2, type X } from '...';  and  export { Name1, Name2 };
    for (const m of src.matchAll(/export\s*\{([^}]+)\}/g)) {
      for (const raw of m[1].split(',')) {
        const id = raw.trim().replace(/^type\s+/, '').split(/\s+as\s+/)[0]?.trim();
        if (id && /^[A-Z_]/.test(id)) {
          if (!map.has(id)) map.set(id, pkg);
        }
      }
    }
  }
  return map;
}

/**
 * Parse a story file by stripping the `import type` line and eval'ing the
 * object literal. Stories must use JSON-serialisable literals only.
 */
async function loadStory(storyPath) {
  const content = await readFile(storyPath, 'utf8');
  const stripped = content.replace(/^import type[^\n]+\n/m, '');
  const match = stripped.match(/export const STORY[^=]*=\s*([\s\S]+?);?\s*$/);
  if (!match) throw new Error(`No STORY export in ${storyPath}`);
  const fn = new Function(`return (${match[1]})`);
  return fn();
}

/**
 * Extract class names from a TS import statement, ignoring `type` keyword.
 * "import { CngxFoo, type FooType } from '...'" → ['CngxFoo', 'FooType']
 */
function importedSymbols(importLine) {
  const m = importLine.match(/import\s*\{([^}]+)\}/);
  if (!m) return [];
  return m[1].split(',').map((s) => s.trim().replace(/^type\s+/, '')).filter(Boolean);
}

/**
 * Build the file-level imports for a generated section component.
 * Returns the import block string + the set of identifiers available.
 */
function buildImports(story, section, importMap) {
  const setup = [story.setup ?? '', section.setup ?? ''].join('\n');
  const tpl = section.template ?? '';
  const usesSignal = /\bsignal\s*[<(]/.test(setup);
  const usesComputed = /\bcomputed\s*[<(]/.test(setup);
  const usesInject = /\binject\s*\(/.test(setup);
  const usesAfterRender = /\bafterNextRender\s*\(/.test(setup);
  const usesEffect = /\beffect\s*\(/.test(setup);
  const usesViewChild = /\bviewChild\s*[<(]/.test(setup);
  const usesElementRef = /\bElementRef\b/.test(setup);
  const usesDestroyRef = /\bDestroyRef\b/.test(setup);

  const coreSymbols = [
    'ChangeDetectionStrategy',
    'Component',
    ...(usesAfterRender ? ['afterNextRender'] : []),
    ...(usesComputed ? ['computed'] : []),
    ...(usesDestroyRef ? ['DestroyRef'] : []),
    ...(usesEffect ? ['effect'] : []),
    ...(usesElementRef ? ['ElementRef'] : []),
    ...(usesInject ? ['inject'] : []),
    ...(usesSignal ? ['signal'] : []),
    ...(usesViewChild ? ['viewChild'] : []),
  ];

  const coreLine = `import { ${coreSymbols.join(', ')} } from '@angular/core';`;

  // Build the haystack: every place a symbol might be referenced in the
  // generated component (TS setup + template HTML).
  const scanText = [story.setup ?? '', section.setup ?? '', section.template ?? ''].join('\n');
  const explicitRefs = new Set([
    ...(section.imports ?? []),
    ...(story.hostDirectives ?? []),
  ]);

  /** Check whether `id` appears as a standalone identifier in scanText. */
  function isReferenced(id) {
    if (explicitRefs.has(id)) return true;
    const re = new RegExp(`\\b${id.replace(/[.*+?^${}()|[\\]\\\\]/g, '\\\\$&')}\\b`);
    return re.test(scanText);
  }

  /** Keep only referenced symbols on an import line; return null if none kept. */
  function filterImportLine(line) {
    const match = line.match(/^(\s*import\s*(?:type\s+)?\{)([^}]+)(\}\s*from\s*['"][^'"]+['"];?\s*)$/);
    if (!match) return line; // non-named-import line — pass through
    const [, head, body, tail] = match;
    const kept = body
      .split(',')
      .map((s) => s.trim())
      .filter(Boolean)
      .filter((spec) => {
        const id = spec.replace(/^type\s+/, '').split(/\s+as\s+/)[0].trim();
        return isReferenced(id);
      });
    if (kept.length === 0) return null;
    return `${head} ${kept.join(', ')} ${tail.trim()}`;
  }

  const filteredModuleImports = (story.moduleImports ?? [])
    .map(filterImportLine)
    .filter((l) => l !== null);

  // Collect identifiers already covered by the filtered moduleImports.
  const coveredIds = new Set();
  for (const line of filteredModuleImports) {
    for (const id of importedSymbols(line)) coveredIds.add(id);
  }

  // Resolve any referenced identifiers still missing via the public-api map.
  const extraByPkg = new Map();
  for (const id of section.imports ?? []) {
    if (coveredIds.has(id)) continue;
    const pkg = importMap.get(id);
    if (!pkg) continue;
    if (!extraByPkg.has(pkg)) extraByPkg.set(pkg, new Set());
    extraByPkg.get(pkg).add(id);
  }
  const extraLines = [...extraByPkg.entries()].map(
    ([pkg, ids]) => `import { ${[...ids].sort().join(', ')} } from '${pkg}';`,
  );

  return { lines: [coreLine, ...filteredModuleImports, ...extraLines] };
}

/** Escape a string for use as a TypeScript single-quoted literal. */
function tsQuote(s) {
  return "'" + String(s).replaceAll('\\', '\\\\').replaceAll("'", "\\'") + "'";
}

/**
 * Escape bare custom-element tags (`<cngx-chart>`, `<my-foo>`) so Angular's
 * innerHTML sanitizer doesn't strip them silently. Known formatting tags
 * (`<code>`, `<strong>`, `<em>`, `<p>`, `<br>`) pass through unchanged.
 */
const SAFE_HTML_TAGS = new Set([
  'a', 'b', 'br', 'code', 'em', 'i', 'kbd', 'mark', 'p', 'pre',
  'span', 'strong', 'sup', 'sub', 'u', 'ul', 'ol', 'li',
]);
function escapeCustomElementTags(html) {
  return String(html).replace(/<\/?([a-zA-Z][a-zA-Z0-9-]*)\b[^>]*>/g, (match, tag) => {
    return SAFE_HTML_TAGS.has(tag.toLowerCase()) ? match : match.replace(/</g, '&lt;').replace(/>/g, '&gt;');
  });
}

function emitComponentSource(meta, story, section, importMap) {
  const { lines } = buildImports(story, section, importMap);
  const setup = [story.setup ?? '', section.setup ?? '']
    .map((b) => (b ?? '').trim())
    .filter(Boolean)
    .join('\n\n');

  // Component-decorator imports (template-level directives/components)
  const tplImports = section.imports ?? [];
  const decoratorImports = tplImports.length > 0 ? `\n  imports: [${tplImports.join(', ')}],` : '';

  // Indent setup body two spaces (it's class-body code)
  const setupBody = setup
    .split('\n')
    .map((l) => (l.trim() ? '  ' + l : ''))
    .join('\n');

  // Intro header: story title + description, then per-section title + subtitle.
  // description/overview/subtitle may contain HTML — render via [innerHTML]
  // bound to class properties so the template parser doesn't choke.
  const introFields = [
    `  protected readonly _exTitle: string = ${tsQuote(story.title ?? '')};`,
    `  protected readonly _exDescription: string = ${tsQuote(escapeCustomElementTags(story.description ?? ''))};`,
    `  protected readonly _exSectionTitle: string = ${tsQuote(section.title ?? '')};`,
    `  protected readonly _exSubtitle: string = ${tsQuote(escapeCustomElementTags(section.subtitle ?? ''))};`,
  ].join('\n');

  const intro = [
    `    <header class="cngx-ex-intro">`,
    `      @if (_exTitle) { <h1>{{ _exTitle }}</h1> }`,
    `      @if (_exDescription) { <p [innerHTML]="_exDescription"></p> }`,
    `      @if (_exSectionTitle && _exSectionTitle !== _exTitle) { <h2>{{ _exSectionTitle }}</h2> }`,
    `      @if (_exSubtitle) { <p class="cngx-ex-hint" [innerHTML]="_exSubtitle"></p> }`,
    `    </header>`,
  ].join('\n');

  const template = section.template.trim();

  return `${GEN_HEADER}
// Source: dev-app/src/app/demos/${meta.demoFolder}/${meta.storyFileName}#section[${meta.sectionIndex}] "${section.title}"

${lines.join('\n')}

@Component({
  selector: 'app-${meta.demoSlug}-${meta.sectionSlug}',
  changeDetection: ChangeDetectionStrategy.OnPush,${decoratorImports}
  template: \`
${intro}
${indent(template, 4)}
  \`,
})
export class ${meta.className} {
${introFields}${setupBody ? '\n' + setupBody : ''}
}
`;
}

function indent(s, n) {
  const pad = ' '.repeat(n);
  return s.split('\n').map((l) => (l.length ? pad + l : l)).join('\n');
}

function emitRoutesSource(routes) {
  const sorted = [...routes].sort((a, b) => a.path.localeCompare(b.path));
  const entries = sorted.map((r) => [
    `  {`,
    `    path: '${r.path}',`,
    `    loadComponent: () => import('./features/${r.demoSlug}/${r.sectionSlug}.component').then((m) => m.${r.className}),`,
    `    data: { lib: '${r.lib}', category: '${r.category}', demo: ${JSON.stringify(r.demoTitle)}, section: ${JSON.stringify(r.sectionTitle)} },`,
    `  },`,
  ].join('\n')).join('\n');

  return `${GEN_HEADER}
import type { Routes } from '@angular/router';

export const routes: Routes = [
${entries}
  {
    path: '',
    loadComponent: () => import('./home/home.component').then((m) => m.HomeComponent),
  },
  { path: '**', redirectTo: '' },
];
`;
}

function emitRoutesMetaSource(routes) {
  const sorted = [...routes].sort((a, b) =>
    (a.lib + a.category + a.demoTitle + a.sectionTitle).localeCompare(
      b.lib + b.category + b.demoTitle + b.sectionTitle,
    ),
  );
  const entries = sorted.map((r) => `  ${JSON.stringify({
    path: r.path,
    lib: r.lib,
    category: r.category,
    demo: r.demoTitle,
    section: r.sectionTitle,
    apiComponents: r.apiComponents,
  })},`).join('\n');
  return `${GEN_HEADER}
export interface RouteMeta {
  path: string;
  lib: string;
  category: string;
  demo: string;
  section: string;
  apiComponents: string[];
}

export const ROUTES_META: readonly RouteMeta[] = [
${entries}
];
`;
}

async function listFolders(dir) {
  try {
    return (await readdir(dir, { withFileTypes: true })).filter((e) => e.isDirectory());
  } catch {
    return [];
  }
}

async function pruneFeaturesDir(approvedSet) {
  const dirs = await listFolders(FEATURES_DIR);
  for (const d of dirs) {
    if (!approvedSet.has(d.name)) {
      await rm(join(FEATURES_DIR, d.name), { recursive: true, force: true });
      console.log(`Removed stale: features/${d.name}/`);
    }
  }
}

async function main() {
  const manifestRaw = await readFile(MANIFEST, 'utf8');
  const manifest = JSON.parse(manifestRaw);
  if (!Array.isArray(manifest.approved)) {
    throw new Error('manifest.approved must be an array of demo folder paths relative to dev-app/src/app/demos/');
  }

  await mkdir(FEATURES_DIR, { recursive: true });

  const importMap = await buildPublicApiImportMap();

  const approvedSlugs = new Set();
  const routes = [];

  for (const rel of manifest.approved) {
    const demoFolder = rel; // e.g. 'common/a11y/active-descendant-demo'
    const demoDir = join(DEMOS_ROOT, demoFolder);
    const files = await readdir(demoDir);
    const storyFiles = files.filter((f) => f.endsWith('.story.ts'));
    if (storyFiles.length === 0) {
      console.warn(`No story in ${demoFolder} — skipping`);
      continue;
    }

    // Use primary story (matches folder name minus -demo). Multi-story dirs aren't expected in SIMPLE.
    const folderLeaf = demoFolder.split('/').pop();
    const primary = storyFiles.find((f) => f === `${folderLeaf}.story.ts`) ?? storyFiles[0];
    const storyPath = join(demoDir, primary);
    const story = await loadStory(storyPath);

    const demoSlug = folderLeaf.replace(/-demo$/, '');
    approvedSlugs.add(demoSlug);
    const featureDir = join(FEATURES_DIR, demoSlug);
    await rm(featureDir, { recursive: true, force: true });
    await mkdir(featureDir, { recursive: true });

    const parts = demoFolder.split('/');
    const lib = parts[0];
    const category = parts.length === 3 ? parts[1] : (story.navCategory ?? '');

    const sections = story.sections ?? [];
    for (let i = 0; i < sections.length; i++) {
      const section = sections[i];
      const cleanedTitle = cleanSectionTitle(section.title);
      let sectionSlug = slugify(cleanedTitle);
      // If cleaning produced an empty slug (e.g. title was only the prefix),
      // fall back to a numbered slug to keep routes unique.
      if (!sectionSlug) sectionSlug = `section-${i + 1}`;
      const className = kebabToPascal(demoSlug) + kebabToPascal(sectionSlug);

      const code = emitComponentSource(
        {
          demoFolder,
          storyFileName: primary,
          sectionIndex: i,
          demoSlug,
          sectionSlug,
          className,
        },
        story,
        section,
        importMap,
      );
      await writeFile(join(featureDir, `${sectionSlug}.component.ts`), code);

      routes.push({
        path: `${demoSlug}/${sectionSlug}`,
        demoSlug,
        sectionSlug,
        className,
        lib,
        category,
        demoTitle: story.title,
        sectionTitle: section.title,
        apiComponents: story.apiComponents ?? [],
      });
    }
    console.log(`Generated ${sections.length} components for ${demoFolder}`);
  }

  await pruneFeaturesDir(approvedSlugs);
  await writeFile(join(EXAMPLES_APP, 'app.routes.ts'), emitRoutesSource(routes));
  await writeFile(join(EXAMPLES_APP, '_routes-meta.ts'), emitRoutesMetaSource(routes));
  console.log(`\nWrote ${routes.length} routes across ${approvedSlugs.size} demos.`);
}

await main().catch((err) => {
  console.error(err);
  process.exit(1);
});
